// Simple full-jitter exponential backoff in JavaScript
async function fetchWithRetry(url, opts = {}) {
  const maxAttempts = opts.maxAttempts || 5;
  const base = opts.base || 100; // ms
  const maxBackoff = opts.maxBackoff || 5000;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const res = await fetch(url, { method: 'POST', headers: { 'Idempotency-Key': opts.idempotencyKey } });
      if (res.ok) return res;
      if (res.status >= 400 && res.status < 500) throw new Error('Client error, do not retry');
    } catch (err) {
      if (attempt === maxAttempts) throw err;
      const backoff = Math.min(maxBackoff, base * Math.pow(2, attempt - 1));
      const sleep = Math.random() * backoff;
      await new Promise(r => setTimeout(r, sleep));
    }
  }
}
